import { useState } from 'react';
import {
    DataGrid,
    DataGridThemeProvider,
    darkTheme,
    roseTheme,
    emeraldTheme,
    amberTheme,
    compactTheme,
    GridPaginationModel,
    GridRowId,
    GridToolbar,
    GridColDef,
    GridFilterModel,
    GridAggregationModel,
    GridPivotModel,
    GridTooltip,
    exportToCsv,
    exportToExcel,
    exportToJson,
    printGrid,
} from '@opencorestack/opengridx';
import type { GridTheme } from '@opencorestack/opengridx';
import { generateEmployees } from '../../data/mockData';
import { allColumns } from '../../data/columns';
import { DocsLayout } from '../../components/DocsLayout';
import './ThemingDemo.css';

import sourceCode from './ThemingDemo.tsx?raw';

const presetThemes: Record<string, GridTheme> = {
    'Default': {},
    'Dark': darkTheme,
    'Rose': roseTheme,
    'Emerald': emeraldTheme,
    'Amber': amberTheme,
    'Compact': compactTheme,
    'Custom Purple': {
        colors: {
            primary: '#7c3aed',
            primaryDark: '#6d28d9',
            primaryLight: '#f5f3ff',
            primaryFocus: 'rgba(124, 58, 237, 0.4)',
        },
        grid: {
            headerBackground: '#f5f3ff',
            rowSelectedBackground: '#ede9fe',
            rowSelectedHoverBackground: '#ddd6fe',
            cellFocusBorder: '#7c3aed',
        },
        borders: {
            radiusLg: '16px',
        },
    },
    'Dark + Compact': {
        ...darkTheme,
        grid: {
            ...darkTheme.grid,
            ...compactTheme.grid,
        },
        typography: compactTheme.typography,
    },
};

const themeColors: Record<string, string> = {
    'Default': '#3b82f6',
    'Dark': '#60a5fa',
    'Rose': '#e11d48',
    'Emerald': '#059669',
    'Amber': '#d97706',
    'Compact': '#3b82f6',
    'Custom Purple': '#7c3aed',
    'Dark + Compact': '#60a5fa',
};

